import pygame
import random

# Initialize Pygame
pygame.init()

# Set the window size
window_width = 800
window_height = 600
window = pygame.display.set_mode((window_width, window_height))
pygame.display.set_caption("Tetris (3 Players)")

# Define colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
BLUE = (0, 0, 255)
GREEN = (0, 255, 0)
RED = (255, 0, 0)

# Define game constants
BLOCK_SIZE = 20
BOARD_WIDTH = 10
BOARD_HEIGHT = 20
PLAYER_BOARD_OFFSET = 100

# Define Tetris shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I-block
    [[1, 1], [1, 1]],  # O-block
    [[1, 1, 1], [0, 1, 0]],  # T-block
    [[1, 1, 1], [1, 0, 0]],  # J-block
    [[1, 1, 1], [0, 0, 1]],  # L-block
    [[1, 1, 0], [0, 1, 1]],  # S-block
    [[0, 1, 1], [1, 1, 0]]  # Z-block
]

# Define Tetris block class
class TetrisBlock:
    def __init__(self, shape, color):
        self.shape = shape
        self.color = color
        self.rotation = 0
        self.x = 3
        self.y = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % len(self.shape)

    def move_left(self):
        self.x = max(self.x - 1, 0)

    def move_right(self):
        self.x = min(self.x + 1, BOARD_WIDTH - len(self.shape[0]))

    def move_down(self):
        self.y += 1

# Define game board class
class GameBoard:
    def __init__(self, player_id):
        self.board = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.current_block = TetrisBlock(random.choice(SHAPES), self.get_player_color(player_id))
        self.score = 0
        self.player_id = player_id

    def get_player_color(self, player_id):
        if player_id == 0:
            return BLUE
        elif player_id == 1:
            return GREEN
        else:
            return RED

    def check_collision(self, block):
        for y, row in enumerate(block.shape[block.rotation]):
            for x, cell in enumerate(row):
                if cell and (
                    x + block.x < 0 or
                    x + block.x >= BOARD_WIDTH or
                    y + block.y >= BOARD_HEIGHT or
                    self.board[y + block.y][x + block.x]
                ):
                    return True
        return False

    def place_block(self):
        for y, row in enumerate(self.current_block.shape[self.current_block.rotation]):
            for x, cell in enumerate(row):
                if cell:
                    self.board[y + self.current_block.y][x + self.current_block.x] = self.current_block.color
        self.current_block = TetrisBlock(random.choice(SHAPES), self.get_player_color(self.player_id))

    def clear_lines(self):
        lines_cleared = 0
        for y in range(BOARD_HEIGHT - 1, -1, -1):
            if all(self.board[y]):
                self.board.pop(y)
                self.board.insert(0, [0] * BOARD_WIDTH)
                lines_cleared += 1
        self.score += lines_cleared ** 2
        return lines_cleared

    def draw(self, x, y):
        for y, row in enumerate(self.board):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(window, cell, (x * BLOCK_SIZE + x, y * BLOCK_SIZE + y, BLOCK_SIZE, BLOCK_SIZE))

        for y, row in enumerate(self.current_block.shape[self.current_block.rotation]):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(window, self.current_block.color, ((x + self.current_block.x) * BLOCK_SIZE + x, (y + self.current_block.y) * BLOCK_SIZE + y, BLOCK_SIZE, BLOCK_SIZE))

# Define game loop
def game_loop():
    clock = pygame.time.Clock()
    game_boards = [GameBoard(i) for i in range(3)]
    game_over = False

    while not game_over:
        clock.tick(30)

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                game_over = True

        # Handle player input
        keys = pygame.key.get_pressed()
        for i, board in enumerate(game_boards):
            if keys[pygame.K_LEFT]:
                board.current_block.move_left()
                if board.check_collision(board.current_block):
                    board.current_block.move_right()
            elif keys[pygame.K_RIGHT]:
                board.current_block.move_right()
                if board.check_collision(board.current_block):
                    board.current_block.move_left()
            elif keys[pygame.K_DOWN]:
                board.current_block.move_down()
                if board.check_collision(board.current_block):
                    board.place_block()
                    lines_cleared = board.clear_lines()
                    print(f"Player {i} cleared {lines_cleared} lines!")
            elif keys[pygame.K_UP]:
                board.current_block.rotate()
                if board.check_collision(board.current_block):
                    board.current_block.rotate()
                    board.current_block.rotate()
                    board.current_block.rotate()

        # Draw the game boards
        window.fill(BLACK)
        for i, board in enumerate(game_boards):
            board.draw(i * PLAYER_BOARD_OFFSET, 0)
            score_text = f"Player {i} Score: {board.score}"
            score_surface = pygame.font.Font(None, 36).render(score_text, True, board.get_player_color(i))
            window.blit(score_surface, (i * PLAYER_BOARD_OFFSET, BOARD_HEIGHT * BLOCK_SIZE + 20))
        pygame.display.flip()

    pygame.quit()

if __name__ == "__main__":
    game_loop()

import pygame
import random

# Define colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
BLUE = (0, 0, 255)
GREEN = (0, 255, 0)
RED = (255, 0, 0)

# Tetris block shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 1], [0, 1, 0]],  # T
    [[1, 1, 1], [1, 0, 0]],  # J
    [[1, 1, 1], [0, 0, 1]],  # L
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]]  # Z
]

# Tetris block colors
COLORS = [BLUE, GREEN, RED, GRAY]

class Tetris:
    def __init__(self, grid_width, grid_height, player_num):
        self.grid_width = grid_width
        self.grid_height = grid_height
        self.player_num = player_num
        self.board = [[0 for _ in range(grid_width)] for _ in range(grid_height)]
        self.current_shape = None
        self.current_x = 0
        self.current_y = 0
        self.current_rotation = 0
        self.score = [0] * player_num
        self.game_over = False

    def new_shape(self):
        self.current_shape = random.choice(SHAPES)
        self.current_x = self.grid_width // 2 - len(self.current_shape[0]) // 2
        self.current_y = 0
        self.current_rotation = 0

    def move_left(self):
        if self.check_collision(self.current_x - 1, self.current_y, self.current_shape, self.current_rotation):
            self.current_x -= 1

    def move_right(self):
        if self.check_collision(self.current_x + 1, self.current_y, self.current_shape, self.current_rotation):
            self.current_x += 1

    def move_down(self):
        if self.check_collision(self.current_x, self.current_y + 1, self.current_shape, self.current_rotation):
            self.current_y += 1
        else:
            self.lock_shape()
            self.new_shape()

    def rotate(self):
        new_rotation = (self.current_rotation + 1) % len(self.current_shape)
        if self.check_collision(self.current_x, self.current_y, self.current_shape, new_rotation):
            self.current_rotation = new_rotation

    def check_collision(self, x, y, shape, rotation):
        for i in range(len(shape[rotation])):
            for j in range(len(shape[rotation][i])):
                if shape[rotation][i][j] == 1:
                    if i + y < 0 or i + y >= self.grid_height or j + x < 0 or j + x >= self.grid_width or self.board[i + y][j + x] != 0:
                        return False
        return True

    def lock_shape(self):
        for i in range(len(self.current_shape[self.current_rotation])):
            for j in range(len(self.current_shape[self.current_rotation][i])):
                if self.current_shape[self.current_rotation][i][j] == 1:
                    self.board[i + self.current_y][j + self.current_x] = (self.player_num + 1) % (self.player_num + 1)
        self.clear_lines()

    def clear_lines(self):
        lines_cleared = 0
        for i in range(self.grid_height):
            if all(self.board[i]):
                self.board.pop(i)
                self.board.insert(0, [0] * self.grid_width)
                lines_cleared += 1
        if lines_cleared > 0:
            self.score[self.player_num] += 10 * lines_cleared ** 2

    def game_over_check(self):
        for x in range(self.grid_width):
            if self.board[0][x] != 0:
                self.game_over = True
                return

class TetrisGame:
    def __init__(self, grid_width, grid_height, player_num):
        self.grid_width = grid_width
        self.grid_height = grid_height
        self.player_num = player_num
        self.tetris_players = [Tetris(self.grid_width, self.grid_height, i) for i in range(self.player_num)]
        self.clock = pygame.time.Clock()
        self.screen = pygame.display.set_mode((self.grid_width * 20 * self.player_num, self.grid_height * 20))
        pygame.display.set_caption("Tetris Collaboration")

    def run(self):
        while True:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    return
                elif event.type == pygame.KEYDOWN:
                    for i in range(self.player_num):
                        if event.key == pygame.K_a:
                            self.tetris_players[i].move_left()
                        elif event.key == pygame.K_d:
                            self.tetris_players[i].move_right()
                        elif event.key == pygame.K_s:
                            self.tetris_players[i].move_down()
                        elif event.key == pygame.K_w:
                            self.tetris_players[i].rotate()

            self.screen.fill(BLACK)

            for i in range(self.player_num):
                self.draw_board(i)
                self.tetris_players[i].move_down()
                self.tetris_players[i].game_over_check()
                if self.tetris_players[i].game_over:
                    self.draw_game_over(i)

            self.draw_scores()
            pygame.display.flip()
            self.clock.tick(30)

    def draw_board(self, player_index):
        for y in range(self.grid_height):
            for x in range(self.grid_width):
                color = self.tetris_players[player_index].board[y][x]
                if color != 0:
                    pygame.draw.rect(self.screen, COLORS[color - 1], (x * 20 + player_index * self.grid_width * 20, y * 20, 20, 20))
                else:
                    pygame.draw.rect(self.screen, GRAY, (x * 20 + player_index * self.grid_width * 20, y * 20, 20, 20), 1)

        for i in range(len(self.tetris_players[player_index].current_shape[self.tetris_players[player_index].current_rotation])):
            for j in range(len(self.tetris_players[player_index].current_shape[self.tetris_players[player_index].current_rotation][i])):
                if self.tetris_players[player_index].current_shape[self.tetris_players[player_index].current_rotation][i][j] == 1:
                    pygame.draw.rect(self.screen, COLORS[player_index], (
                        (self.tetris_players[player_index].current_x + j) * 20 + player_index * self.grid_width * 20,
                        (self.tetris_players[player_index].current_y + i) * 20, 20, 20))

    def draw_scores(self):
        font = pygame.font.Font(None, 36)
        text = font.render("Scores:", True, WHITE)
        self.screen.blit(text, (10, 10))
        for i in range(self.player_num):
            text = font.render(f"Player {i+1}: {self.tetris_players[i].score[i]}", True, COLORS[i])
            self.screen.blit(text, (10, 40 + i * 30))

    def draw_game_over(self, player_index):
        font = pygame.font.Font(None, 72)
        text = font.render("Game Over", True, RED)
        self.screen.blit(text, (self.grid_width * 20 * player_index + self.grid_width * 10, self.grid_height * 10))

if __name__ == "__main__":
    pygame.init()
    game = TetrisGame(10, 20, 3)
    game.run()

import pygame
import random

# Define the game window dimensions
WINDOW_WIDTH = 800
WINDOW_HEIGHT = 600

# Define the Tetris board dimensions
BOARD_WIDTH = 10
BOARD_HEIGHT = 20

# Define the block size
BLOCK_SIZE = 30

# Define the colors
COLORS = [(0, 0, 255), (0, 255, 0), (255, 0, 0), (255, 255, 0), (255, 0, 255), (0, 255, 255)]

# Define the Tetris shapes
SHAPES = [
    [[1, 1, 1, 1]],
    [[0, 2, 2], [2, 2, 0]],
    [[3, 3, 0], [0, 3, 3]],
    [[4, 0, 0], [4, 4, 4]],
    [[0, 0, 5], [5, 5, 5]],
    [[6, 6, 6, 0]],
    [[0, 6, 6], [6, 6, 0]]
]

class Tetromino:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color
        self.rotation = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % len(self.shape)

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

    def get_blocks(self):
        blocks = []
        for y, row in enumerate(self.shape[self.rotation]):
            for x, block in enumerate(row):
                if block:
                    blocks.append((self.x + x, self.y + y))
        return blocks

class Board:
    def __init__(self):
        self.grid = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.score = 0

    def add_tetromino(self, tetromino):
        for x, y in tetromino.get_blocks():
            if y >= 0:
                self.grid[y][x] = tetromino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(BOARD_HEIGHT - 1, -1, -1):
            if all(self.grid[y]):
                self.grid.pop(y)
                self.grid.insert(0, [0] * BOARD_WIDTH)
                lines_cleared += 1
        self.score += lines_cleared ** 2
        return lines_cleared

    def game_over(self):
        for x in range(BOARD_WIDTH):
            if self.grid[0][x]:
                return True
        return False

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WINDOW_WIDTH, WINDOW_HEIGHT))
        pygame.display.set_caption("Tetris")
        self.clock = pygame.time.Clock()
        self.boards = [Board() for _ in range(3)]
        self.tetrominos = [self.new_tetromino() for _ in range(3)]
        self.running = True

    def new_tetromino(self):
        shape = random.choice(SHAPES)
        color = random.choice(COLORS)
        return Tetromino(BOARD_WIDTH // 2 - len(shape[0]) // 2, 0, shape, color)

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False
            elif event.type == pygame.KEYDOWN:
                for i, board in enumerate(self.boards):
                    if event.key == pygame.K_LEFT:
                        self.move_tetromino(i, -1, 0)
                    elif event.key == pygame.K_RIGHT:
                        self.move_tetromino(i, 1, 0)
                    elif event.key == pygame.K_DOWN:
                        self.move_tetromino(i, 0, 1)
                    elif event.key == pygame.K_UP:
                        self.rotate_tetromino(i)

    def move_tetromino(self, player_index, dx, dy):
        tetromino = self.tetrominos[player_index]
        if all(x >= 0 and x < BOARD_WIDTH and y >= 0 and y < BOARD_HEIGHT and self.boards[player_index].grid[y][x] == 0
              for x, y in tetromino.get_blocks()):
            tetromino.move(dx, dy)

    def rotate_tetromino(self, player_index):
        tetromino = self.tetrominos[player_index]
        old_rotation = tetromino.rotation
        tetromino.rotate()
        if any(x < 0 or x >= BOARD_WIDTH or y >= BOARD_HEIGHT for x, y in tetromino.get_blocks()):
            tetromino.rotation = old_rotation

    def update(self):
        for i, board in enumerate(self.boards):
            tetromino = self.tetrominos[i]
            self.move_tetromino(i, 0, 1)
            if any(y >= BOARD_HEIGHT - 1 or self.boards[i].grid[y + 1][x] for x, y in tetromino.get_blocks()):
                board.add_tetromino(tetromino)
                lines_cleared = board.clear_lines()
                if lines_cleared > 0:
                    print(f"Player {i+1} cleared {lines_cleared} lines!")
                self.tetrominos[i] = self.new_tetromino()

    def draw(self):
        self.screen.fill((0, 0, 0))
        for i, board in enumerate(self.boards):
            for y in range(BOARD_HEIGHT):
                for x in range(BOARD_WIDTH):
                    if board.grid[y][x]:
                        pygame.draw.rect(self.screen, COLORS[board.grid[y][x] - 1],
                                        (i * (BOARD_WIDTH + 2) * BLOCK_SIZE + x * BLOCK_SIZE,
                                         y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
            for x, y in self.tetrominos[i].get_blocks():
                pygame.draw.rect(self.screen, COLORS[self.tetrominos[i].color - 1],
                                (i * (BOARD_WIDTH + 2) * BLOCK_SIZE + x * BLOCK_SIZE,
                                 y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
            score_text = f"Player {i+1} Score: {board.score}"
            text = pygame.font.Font(None, 36).render(score_text, True, (255, 255, 255))
            self.screen.blit(text, (i * (BOARD_WIDTH + 2) * BLOCK_SIZE, BOARD_HEIGHT * BLOCK_SIZE + 10))
        pygame.display.flip()

    def run(self):
        while self.running:
            self.clock.tick(60)
            self.handle_events()
            self.update()
            self.draw()
            if any(board.game_over() for board in self.boards):
                self.running = False

        pygame.quit()

if __name__ == "__main__":
    game = Game()
    game.run()

