import pygame
import random

# Constants
WINDOW_WIDTH = 800
WINDOW_HEIGHT = 600
BLOCK_SIZE = 30
GRID_WIDTH = 10
GRID_HEIGHT = 20
PLAYER_COUNT = 3

# Colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
COLORS = [(255, 0, 0), (0, 255, 0), (0, 0, 255)]

# Tetromino shapes
TETROMINOS = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 1], [0, 1, 0]],  # T
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]]  # Z
]

class Tetromino:
    def __init__(self, shape, color):
        self.shape = shape
        self.color = color
        self.rotation = 0
        self.x = 3
        self.y = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % len(self.shape)

    def move_left(self):
        self.x = max(self.x - 1, 0)

    def move_right(self):
        self.x = min(self.x + 1, GRID_WIDTH - len(self.shape[0]))

    def move_down(self):
        self.y += 1

class Grid:
    def __init__(self, player_id):
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.player_id = player_id
        self.score = 0
        self.lines_cleared = 0

    def add_tetromino(self, tetromino):
        for y, row in enumerate(tetromino.shape[tetromino.rotation]):
            for x, cell in enumerate(row):
                if cell:
                    self.grid[tetromino.y + y][tetromino.x + x] = tetromino.color

    def check_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT - 1, -1, -1):
            if all(self.grid[y]):
                self.grid.pop(y)
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        self.lines_cleared += lines_cleared
        self.score += lines_cleared ** 2 * 100
        return lines_cleared

    def game_over(self):
        for x in range(GRID_WIDTH):
            if self.grid[0][x]:
                return True
        return False

class Game:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((WINDOW_WIDTH, WINDOW_HEIGHT))
        pygame.display.set_caption("Tetris (Collaborative)")
        self.clock = pygame.time.Clock()
        self.grids = [Grid(i) for i in range(PLAYER_COUNT)]
        self.current_tetrominos = [Tetromino(random.choice(TETROMINOS), COLORS[i]) for i in range(PLAYER_COUNT)]
        self.game_over = False

    def draw_grid(self, grid, x, y):
        for j in range(GRID_HEIGHT):
            for i in range(GRID_WIDTH):
                color = grid.grid[j][i]
                if color:
                    pygame.draw.rect(self.screen, color, (x + i * BLOCK_SIZE, y + j * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))
                else:
                    pygame.draw.rect(self.screen, BLACK, (x + i * BLOCK_SIZE, y + j * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 1)

    def draw_tetromino(self, tetromino, x, y):
        for j, row in enumerate(tetromino.shape[tetromino.rotation]):
            for i, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(self.screen, tetromino.color, (x + i * BLOCK_SIZE, y + j * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

    def update_game(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return True
            elif event.type == pygame.KEYDOWN:
                for i in range(PLAYER_COUNT):
                    if event.key == pygame.K_LEFT:
                        self.current_tetrominos[i].move_left()
                    elif event.key == pygame.K_RIGHT:
                        self.current_tetrominos[i].move_right()
                    elif event.key == pygame.K_DOWN:
                        self.current_tetrominos[i].move_down()
                    elif event.key == pygame.K_UP:
                        self.current_tetrominos[i].rotate()

        for i in range(PLAYER_COUNT):
            if self.grids[i].game_over():
                self.game_over = True
                return False

        for i in range(PLAYER_COUNT):
            self.grids[i].add_tetromino(self.current_tetrominos[i])
            self.grids[i].check_lines()

        for i in range(PLAYER_COUNT):
            self.current_tetrominos[i].move_down()

        for i in range(PLAYER_COUNT):
            if self.current_tetrominos[i].y >= GRID_HEIGHT:
                self.current_tetrominos[i] = Tetromino(random.choice(TETROMINOS), COLORS[i])

        return False

    def draw_game(self):
        self.screen.fill(WHITE)

        for i in range(PLAYER_COUNT):
            self.draw_grid(self.grids[i], i * (WINDOW_WIDTH // PLAYER_COUNT), 0)
            self.draw_tetromino(self.current_tetrominos[i], i * (WINDOW_WIDTH // PLAYER_COUNT) + self.current_tetrominos[i].x * BLOCK_SIZE, self.current_tetrominos[i].y * BLOCK_SIZE)

            # Display player score and lines cleared
            font = pygame.font.Font(None, 36)
            score_text = font.render(f"Player {i+1} - Score: {self.grids[i].score}", True, BLACK)
            lines_cleared_text = font.render(f"Lines Cleared: {self.grids[i].lines_cleared}", True, BLACK)
            self.screen.blit(score_text, (i * (WINDOW_WIDTH // PLAYER_COUNT) + 10, GRID_HEIGHT * BLOCK_SIZE + 10))
            self.screen.blit(lines_cleared_text, (i * (WINDOW_WIDTH // PLAYER_COUNT) + 10, GRID_HEIGHT * BLOCK_SIZE + 50))

        if self.game_over:
            font = pygame.font.Font(None, 72)
            game_over_text = font.render("Game Over", True, BLACK)
            self.screen.blit(game_over_text, (WINDOW_WIDTH // 2 - 150, WINDOW_HEIGHT // 2 - 36))

