# Define the Tetris shapes
SHAPES = [
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Square
    [(0, 0), (0, 1), (0, 2), (0, 3)],  # I
    [(0, 0), (0, 1), (0, 2), (1, 2)],  # L
    [(0, 0), (0, 1), (0, 2), (1, 0)],  # J
    [(0, 0), (0, 1), (1, 1), (1, 2)],  # S
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Z
    [(0, 0), (0, 1), (0, 2), (1, 1)],  # T
]

class Tetromino:
    def __init__(self, shape_index, player_index):
        self.shape = SHAPES[shape_index]
        self.color = COLORS[player_index]
        self.x = 3
        self.y = 0
        self.rotation = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % 4
        self.shape = [(-y, x) for x, y in self.shape]

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

    def get_blocks(self):
        return [(self.x + x, self.y + y) for x, y in self.shape]

class Board:
    def __init__(self, player_index):
        self.board = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.player_index = player_index
        self.score = 0

    def add_tetromino(self, tetromino):
        for x, y in tetromino.get_blocks():
            if y >= 0:
                self.board[y][x] = tetromino.color

    def check_lines(self):
        lines_cleared = 0
        for y in range(BOARD_HEIGHT - 1, -1, -1):
            if all(self.board[y]):
                self.board.pop(y)
                self.board.insert(0, [0] * BOARD_WIDTH)
                lines_cleared += 1
        self.score += lines_cleared ** 2
        return lines_cleared

    def game_over(self):
        for x in range(BOARD_WIDTH):
            if self.board[0][x] != 0:
                return True
        return False

class TetrisGame:
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((BOARD_WIDTH * (BLOCK_SIZE + BLOCK_GAP) * 3, BOARD_HEIGHT * (BLOCK_SIZE + BLOCK_GAP)))
        pygame.display.set_caption("Collaborative Tetris")
        self.clock = pygame.time.Clock()
        self.boards = [Board(i) for i in range(3)]
        self.tetrominos = [Tetromino(random.randint(0, len(SHAPES) - 1), i) for i in range(3)]
        self.running = True

    def run(self):
        while self.running:
            self.handle_events()
            self.update()
            self.draw()
            self.clock.tick(60)

        pygame.quit()

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False

            for i in range(3):
                if event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_a:
                        self.tetrominos[i].move(-1, 0)
                    elif event.key == pygame.K_d:
                        self.tetrominos[i].move(1, 0)
                    elif event.key == pygame.K_s:
                        self.tetrominos[i].move(0, 1)
                    elif event.key == pygame.K_w:
                        self.tetrominos[i].rotate()

    def update(self):
        for i in range(3):
            if not self.check_collision(self.tetrominos[i], 0, 1):
                self.tetrominos[i].move(0, 1)
            else:
                self.boards[i].add_tetromino(self.tetrominos[i])
                lines_cleared = self.boards[i].check_lines()
                print(f"Player {i} cleared {lines_cleared} lines!")
                self.tetrominos[i] = Tetromino(random.randint(0, len(SHAPES) - 1), i)

            if self.boards[i].game_over():
                self.running = False
                print(f"Player {i} lost!")

    def check_collision(self, tetromino, dx, dy):
        for x, y in tetromino.get_blocks():
            new_x, new_y = x + dx, y + dy
            if new_x < 0 or new_x >= BOARD_WIDTH or new_y >= BOARD_HEIGHT:
                return True
            if new_y >= 0 and self.boards[tetromino.player_index].board[new_y][new_x] != 0:
                return True
        return False

    def draw(self):
        self.screen.fill((0, 0, 0))

        for i in range(3):
            for y in range(BOARD_HEIGHT):
                for x in range(BOARD_WIDTH):
                    if self.boards[i].board[y][x] != 0:
                        color = self.boards[i].board[y][x]
                        rect = pygame.Rect(x * (BLOCK_SIZE + BLOCK_GAP) + i * BOARD_WIDTH * (BLOCK_SIZE + BLOCK_GAP), y * (BLOCK_SIZE + BLOCK_GAP), BLOCK_SIZE, BLOCK_SIZE)
                        pygame.draw.rect(self.screen, color, rect)

            for block in self.tetrominos[i].get_blocks():
                x, y = block
                rect = pygame.Rect(x * (BLOCK_SIZE + BLOCK_GAP) + i * BOARD_WIDTH * (BLOCK_SIZE + BLOCK_GAP), y * (BLOCK_SIZE + BLOCK_GAP), BLOCK_SIZE, BLOCK_SIZE)
                pygame.draw.rect(self.screen, self.tetrominos[i].color, rect)

            score_text = f"Player {i} Score: {self.boards[i].score}"
            score_surface = pygame.font.Font(None, 36).render(score_text, True, (255, 255, 255))
            self.screen.blit(score_surface, (i * BOARD_WIDTH * (BLOCK_SIZE + BLOCK_GAP), BOARD_HEIGHT * (BLOCK_SIZE + BLOCK_GAP)))

        pygame.display.flip()

