        self.current_tetromino.move(0, 1)
        if self.check_collision():
            self.current_tetromino.move(0, -1)
            self.lock_tetromino()
            self.clear_lines()
            self.spawn_tetromino()

    def check_collision(self):
        tetromino = self.current_tetromino
        for y, row in enumerate(tetromino.shape[tetromino.rotation]):
