import pygame
import random

# Define the game board dimensions
BOARD_WIDTH = 10
BOARD_HEIGHT = 20

# Define the tetromino shapes
TETROMINOS = [
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Square
    [(0, 0), (0, 1), (0, 2), (0, 3)],  # I-shaped
    [(0, 0), (0, 1), (0, 2), (1, 2)],  # L-shaped
    [(0, 0), (0, 1), (0, 2), (1, 0)],  # J-shaped
    [(0, 0), (0, 1), (1, 1), (1, 0)],  # Z-shaped
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # S-shaped
    [(0, 0), (0, 1), (0, 2), (1, 1)],  # T-shaped
]

# Define the colors for the tetrominos
TETROMINO_COLORS = [(255, 255, 0), (0, 255, 255), (255, 165, 0), (0, 0, 255), (255, 0, 0), (0, 255, 0), (128, 0, 128)]

class Tetromino:
    def __init__(self, shape, color, x, y):
        self.shape = shape
        self.color = color
        self.x = x
        self.y = y

    def rotate(self):
        self.shape = [(y, -x) for x, y in self.shape]

    def move_left(self):
        self.x -= 1

    def move_right(self):
        self.x += 1

    def move_down(self):
        self.y += 1

class Board:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.grid = [[0 for _ in range(width)] for _ in range(height)]

    def add_tetromino(self, tetromino):
        for x, y in tetromino.shape:
            self.grid[tetromino.y + y][tetromino.x + x] = tetromino.color

    def check_full_rows(self):
        full_rows = 0
        for y in range(self.height - 1, -1, -1):
            if all(self.grid[y]):
                self.grid.pop(y)
                self.grid.insert(0, [0] * self.width)
                full_rows += 1
        return full_rows

class Player:
    def __init__(self, name):
        self.name = name
        self.score = 0

    def update_score(self, rows_cleared):
        self.score += rows_cleared * 100

class TetrisGame:
    def __init__(self, num_players):
        self.num_players = num_players
        self.players = [Player(f"Player {i+1}") for i in range(num_players)]
        self.boards = [Board(BOARD_WIDTH, BOARD_HEIGHT) for _ in range(num_players)]
        self.current_tetrominos = [self.spawn_tetromino() for _ in range(num_players)]

    def spawn_tetromino(self):
        shape = random.choice(TETROMINOS)
        color = random.choice(TETROMINO_COLORS)
        return Tetromino(shape, color, BOARD_WIDTH // 2 - 2, 0)

    def move_tetrominos(self):
        for i in range(self.num_players):
            if self.can_move_down(i):
                self.current_tetrominos[i].move_down()
            else:
                self.boards[i].add_tetromino(self.current_tetrominos[i])
                rows_cleared = self.boards[i].check_full_rows()
                self.players[i].update_score(rows_cleared)
                self.current_tetrominos[i] = self.spawn_tetromino()

    def can_move_down(self, player_index):
        tetromino = self.current_tetrominos[player_index]
        for x, y in tetromino.shape:
            new_y = tetromino.y + y + 1
            new_x = tetromino.x + x
            if new_y >= BOARD_HEIGHT or self.boards[player_index].grid[new_y][new_x]:
                return False
        return True

    def run(self):
        pygame.init()
        screen = pygame.display.set_mode((BOARD_WIDTH * 30, BOARD_HEIGHT * 30))
        pygame.display.set_caption("Tetris")

        clock = pygame.time.Clock()
        running = True
        while running:
            clock.tick(60)
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    running = False

            screen.fill((0, 0, 0))

            for i in range(self.num_players):
                for y in range(BOARD_HEIGHT):
                    for x in range(BOARD_WIDTH):
                        if self.boards[i].grid[y][x]:
                            pygame.draw.rect(screen, self.boards[i].grid[y][x], (x * 30, y * 30, 30, 30))
                        pygame.draw.rect(screen, (128, 128, 128), (x * 30, y * 30, 30, 30), 1)

                for x, y in self.current_tetrominos[i].shape:
                    pygame.draw.rect(screen, self.current_tetrominos[i].color, ((self.current_tetrominos[i].x + x) * 30, (self.current_tetrominos[i].y + y) * 30, 30, 30))

                for j, player in enumerate(self.players):
                    font = pygame.font.Font(None, 36)
                    text = font.render(f"{player.name}: {player.score}", True, (255, 255, 255))
                    screen.blit(text, (BOARD_WIDTH * 30 + 20, j * 50))

            self.move_tetrominos()
            pygame.display.flip()

        pygame.quit()

if __name__ == "__main__":
    game = TetrisGame(3)
    game.run()

