        ]
        self.game_over = False
        self.screen = pygame.display.set_mode((WINDOW_WIDTH, WINDOW_HEIGHT))
        pygame.display.set_caption("Tetris")

    def check_collision(self, player, dx, dy):
        tetromino = player.tetromino
        for y, row in enumerate(tetromino.shape[tetromino.rotation]):
            for x, block in enumerate(row):
                if block:
                    new_x = tetromino.x + x + dx
                    new_y = tetromino.y + y + dy
                    if new_x < 0 or new_x >= 10 or new_y >= 20 or (new_y >= 0 and self.board[new_y][new_x]):
                        return True
