import pygame
import random

# Define the game window dimensions
WINDOW_WIDTH = 800
WINDOW_HEIGHT = 600

# Define the Tetris board dimensions
BOARD_WIDTH = 10
BOARD_HEIGHT = 20

# Define the size of each Tetris block
BLOCK_SIZE = 30

# Define the colors for the Tetris blocks
COLORS = [(0, 0, 255), (0, 255, 0), (255, 0, 0), (255, 255, 0), (255, 0, 255), (0, 255, 255), (128, 128, 128)]

# Define the Tetris shapes
SHAPES = [
    [[1, 5, 9, 13], [4, 5, 6, 7]],
    [[1, 2, 5, 9], [0, 4, 5, 6], [1, 5, 9, 8], [4, 5, 6, 10]],
    [[1, 2, 6, 10], [5, 6, 7, 9], [2, 6, 10, 11], [3, 5, 6, 7]],
    [[1, 4, 5, 6], [1, 4, 5, 9], [4, 5, 6, 9], [1, 5, 6, 9]],
    [[1, 2, 5, 6]],
    [[1, 4, 5, 6], [1, 4, 5, 8], [4, 5, 6, 9], [1, 5, 8, 9]],
    [[1, 2, 3, 5], [1, 4, 5, 6], [1, 5, 6, 9], [4, 5, 6, 7]]
]

class Tetris:
    def __init__(self, player_name):
        self.player_name = player_name
        self.board = [[0 for x in range(BOARD_WIDTH)] for y in range(BOARD_HEIGHT)]
        self.current_piece = self.new_piece()
        self.score = 0
        self.level = 1
        self.fall_time = 0.5

    def new_piece(self):
        return [SHAPES[random.randint(0, len(SHAPES) - 1)], 3, 0]

    def move(self, dx, dy):
        new_x = self.current_piece[1] + dx
        new_y = self.current_piece[2] + dy
        if self.check_valid_position(self.current_piece[0], new_x, new_y):
            self.current_piece[1] = new_x
            self.current_piece[2] = new_y

    def rotate(self):
        self.current_piece[0] = self.get_rotated_piece(self.current_piece[0])
        if not self.check_valid_position(self.current_piece[0], self.current_piece[1], self.current_piece[2]):
            self.current_piece[0] = self.get_rotated_piece(self.current_piece[0], reverse=True)

    def get_rotated_piece(self, piece, reverse=False):
        if reverse:
            return piece[::-1]
        else:
            return [piece[i] for i in (1, 2, 3, 0)]

    def check_valid_position(self, piece, x, y):
        for i in range(4):
            p_x = x + piece[i] % 4
            p_y = y + piece[i] // 4
            if p_x < 0 or p_x >= BOARD_WIDTH or p_y >= BOARD_HEIGHT:
                return False
            if self.board[p_y][p_x] != 0:
                return False
        return True

    def freeze_piece(self):
        for i in range(4):
            x = self.current_piece[1] + self.current_piece[0][i] % 4
            y = self.current_piece[2] + self.current_piece[0][i] // 4
            self.board[y][x] = self.current_piece[0][i] // 4 + 1
        self.current_piece = self.new_piece()
        self.clear_lines()

    def clear_lines(self):
        lines_cleared = 0
        for i in range(BOARD_HEIGHT - 1, -1, -1):
            if 0 not in self.board[i]:
                self.board.pop(i)
                self.board.insert(0, [0 for _ in range(BOARD_WIDTH)])
                lines_cleared += 1
        if lines_cleared > 0:
            self.score += 100 * lines_cleared ** 2
            self.level = self.score // 1000 + 1
            self.fall_time = max(0.1, self.fall_time - 0.05)

    def draw(self, surface):
        for y in range(BOARD_HEIGHT):
            for x in range(BOARD_WIDTH):
                if self.board[y][x] != 0:
                    pygame.draw.rect(surface, COLORS[self.board[y][x] - 1], (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 0)

        for i in range(4):
            x = self.current_piece[1] + self.current_piece[0][i] % 4
            y = self.current_piece[2] + self.current_piece[0][i] // 4
            pygame.draw.rect(surface, COLORS[self.current_piece[0][i] // 4], (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE), 0)

def main():
    pygame.init()
    screen = pygame.display.set_mode((WINDOW_WIDTH, WINDOW_HEIGHT))
    pygame.display.set_caption("Tetris")

    # Create three Tetris players
    player1 = Tetris("Player 1")
    player2 = Tetris("Player 2")
    player3 = Tetris("Player 3")

    clock = pygame.time.Clock()
    running = True
    while running:
        # Handle events
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    player1.move(-1, 0)
                elif event.key == pygame.K_RIGHT:
                    player1.move(1, 0)
                elif event.key == pygame.K_DOWN:
                    player1.move(0, 1)
                elif event.key == pygame.K_UP:
                    player1.rotate()
                elif event.key == pygame.K_a:
                    player2.move(-1, 0)
                elif event.key == pygame.K_d:
                    player2.move(1, 0)
                elif event.key == pygame.K_s:
                    player2.move(0, 1)
                elif event.key == pygame.K_w:
                    player2.rotate()
                elif event.key == pygame.K_j:
                    player3.move(-1, 0)
                elif event.key == pygame.K_l:
                    player3.move(1, 0)
                elif event.key == pygame.K_k:
                    player3.move(0, 1)
                elif event.key == pygame.K_i:
                    player3.rotate()

        # Update game state
        player1.fall_time += clock.get_rawtime() / 1000
        player2.fall_time += clock.get_rawtime() / 1000
        player3.fall_time += clock.get_rawtime() / 1000

        if player1.fall_time > player1.fall_time:
            player1.fall_time = 0
            if not player1.check_valid_position(player1.current_piece[0], player1.current_piece[1], player1.current_piece[2] + 1):
                player1.freeze_piece()
            else:
                player1.move(0, 1)

        if player2.fall_time > player2.fall_time:
            player2.fall_time = 0
            if not player2.check_valid_position(player2.current_piece[0], player2.current_piece[1], player2.current_piece[2] + 1):
