        if self.next_tetromino is None:
            self.next_tetromino = Tetromino(self.grid_width // 2 - 2, 0, random.randint(0, len(Tetromino.shapes) - 1))
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = Tetromino(self.grid_width // 2 - 2, 0, random.randint(0, len(Tetromino.shapes) - 1))

