        for y in range(self.grid_height):
            for x in range(self.grid_width):
                self.grid[y][x] = 0

        for player_tetromino in [self.current_tetromino]:
            for y in range(len(player_tetromino.shape)):
                for x in range(len(player_tetromino.shape[y])):
                    if player_tetromino.shape[y][x] == 1:
                        self.grid[player_tetromino.y + y][player_tetromino.x + x] = 1

