class TetrisBlock:
    def __init__(self, x, y, shape, color):
        self.x = x
        self.y = y
        self.shape = shape
        self.color = color

    def rotate(self):
        self.shape = [list(reversed(col)) for col in zip(*self.shape)]

    def move(self, dx, dy):
