        if self.check_valid_position(new_shape, self.current_pos):
            self.current_shape = new_shape

    def move_shape(self, dx, dy):
        new_pos = [self.current_pos[0] + dx, self.current_pos[1] + dy]
        if self.check_valid_position(self.current_shape, new_pos):
            self.current_pos = new_pos

    def drop_shape(self):
        while self.check_valid_position(self.current_shape, [self.current_pos[0], self.current_pos[1] + 1]):
