            self.update_scores(lines_cleared)

    def update_scores(self, lines_cleared):
        for i in range(3):
            self.score[i] += lines_cleared * 100

class Piece:
    def __init__(self, shape, x, y, points, cost):
        self.shape = shape
        self.x = x
        self.y = y
        self.points = points
        self.cost = cost

    def rotate(self):
        self.shape = list(zip(*self.shape[::-1]))

class Player:
    def __init__(self, name):
        self.name = name
        self.score = 0
        self.wad = 0

    def update_score(self, score):
        self.score += score

    def update_wad(self, wad):
        self.wad += wad

class Game:
    def __init__(self):
        pygame.init()
        self.board = TetrisBoard(10, 20)
        self.players = [Player("Player 1"), Player("Player 2"), Player("Player 3")]
        self.current_piece = self.get_random_piece()
        self.clock = pygame.time.Clock()
        self.window = pygame.display.set_mode((800, 600))
        pygame.display.set_caption("Tetris")

    def get_random_piece(self):
        shapes = [
            [[1, 1, 1, 1]], # I
            [[1, 1], [1, 1]], # O
            [[1, 1, 0], [0, 1, 1]], # Z
            [[0, 1, 1], [1, 1, 0]], # S
            [[1, 0, 0], [1, 1, 1]], # J
            [[0, 0, 1], [1, 1, 1]], # L
            [[1, 1, 1], [0, 1, 0]] # T
        ]
        points = [400, 100, 200, 200, 300, 300, 300]
        costs = [100, 50, 75, 75, 100, 100, 100]
        index = random.randint(0, len(shapes) - 1)
        return Piece(shapes[index], 3, 0, points[index], costs[index])

    def run(self):
        while True:
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    pygame.quit()
                    return

            self.handle_input()
            self.update()
            self.draw()
            self.clock.tick(60)

    def handle_input(self):
        keys = pygame.key.get_pressed()
        if keys[pygame.K_LEFT]:
            self.current_piece.x -= 1
            if self.check_collision(self.current_piece):
                self.current_piece.x += 1
        elif keys[pygame.K_RIGHT]:
            self.current_piece.x += 1
            if self.check_collision(self.current_piece):
                self.current_piece.x -= 1
        elif keys[pygame.K_DOWN]:
            self.current_piece.y += 1
            if self.check_collision(self.current_piece):
                self.current_piece.y -= 1
                self.board.add_piece(self.current_piece, self.get_current_player_index())
                self.current_piece = self.get_random_piece()
        elif keys[pygame.K_UP]:
            self.current_piece.rotate()
            if self.check_collision(self.current_piece):
                self.current_piece.rotate()
                self.current_piece.rotate()
                self.current_piece.rotate()

    def update(self):
        self.current_piece.y += 1
        if self.check_collision(self.current_piece):
            self.current_piece.y -= 1
            self.board.add_piece(self.current_piece, self.get_current_player_index())
            self.current_piece = self.get_random_piece()

    def draw(self):
        self.window.fill((0, 0, 0))
        self.draw_board()
        self.draw_piece(self.current_piece)
        self.draw_scores()
        pygame.display.flip()

    def draw_board(self):
        for y, row in enumerate(self.board.grid):
            for x, block in enumerate(row):
                if block:
                    color = (255, 255, 255) if block == 1 else (0, 255, 0) if block == 2 else (0, 0, 255)
                    pygame.draw.rect(self.window, color, (x * 30, y * 30, 30, 30))

    def draw_piece(self, piece):
        for y, row in enumerate(piece.shape):
            for x, block in enumerate(row):
                if block:
                    pygame.draw.rect(self.window, (255, 255, 255), ((piece.x + x) * 30, (piece.y + y) * 30, 30, 30))

    def draw_scores(self):
        font = pygame.font.Font(None, 36)
        for i, player in enumerate(self.players):
            text = font.render(f"{player.name}: Score {player.score}, Wad {player.wad}", True, (255, 255, 255))
            self.window.blit(text, (10, 10 + i * 50))

    def check_collision(self, piece):
        for y, row in enumerate(piece.shape):
            for x, block in enumerate(row):
                if block:
                    if piece.x + x < 0 or piece.x + x >= self.board.width or piece.y + y >= self.board.height or self.board.grid[piece.y + y][piece.x + x]:
                        return True
        return False

    def get_current_player_index(self):
        return self.board.score.index(max(self.board.score))

if __name__ == "__main__":
    game = Game()
    game.run()

