    [(0, 0), (0, 1), (0, 2), (1, 0)],  # L-shape
    [(0, 0), (0, 1), (0, 2), (1, 2)],  # J-shape
    [(0, 0), (0, 1), (1, 1), (1, 0)],  # Z-shape
    [(0, 0), (0, 1), (1, 0), (1, 1)]   # S-shape
]

# Game state
player_scores = [0, 0, 0]
player_tetrominos = [None, None, None]
game_over = False

def rotate_tetromino(tetromino):
    return [(y, -x) for x, y in tetromino]

def get_tetromino_position(tetromino, x, y):
    return [(x + dx, y + dy) for dx, dy in tetromino]

def check_collision(grid, tetromino, x, y):
    for dx, dy in tetromino:
        nx, ny = x + dx, y + dy
        if nx < 0 or nx >= GRID_SIZE or ny >= GRID_SIZE or grid[ny][nx]:
            return True
    return False

def clear_lines(grid):
    lines_cleared = 0
    for y in range(GRID_SIZE - 1, -1, -1):
        if all(grid[y]):
            del grid[y]
            grid.insert(0, [False] * GRID_SIZE)
            lines_cleared += 1
    return lines_cleared

def update_game_state(grid, tetromino, x, y):
    for dx, dy in tetromino:
        grid[y + dy][x + dx] = True
    lines_cleared = clear_lines(grid)
    return lines_cleared

