    global game_over
    clock = pygame.time.Clock()

    grids = [[False] * GRID_SIZE for _ in range(GRID_SIZE)]
    player_indices = [0, 1, 2]
    random.shuffle(player_indices)

    while not game_over:
        clock.tick(int(1 / GAME_SPEED))

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                game_over = True

        for player_index in player_indices:
            if player_tetrominos[player_index] is None:
