                update_player_scores(lines_cleared, player_index)
                player_tetrominos[player_index] = None
            else:
                y += 1

        # Draw the game
        screen.fill(BLACK)
        draw_grid(grids)
        for player_index, tetromino in enumerate(player_tetrominos):
            if tetromino is not None:
                draw_tetromino(tetromino, x, y, BLOCK_COLORS[player_index])
        pygame.display.flip()

    pygame.quit()

game_loop()

