RED = (255, 0, 0)

# Tetromino shapes
TETROMINOS = [
    [[1, 1, 1, 1]],  # I
    [[1, 1], [1, 1]],  # O
    [[1, 1, 1], [0, 1, 0]],  # T
    [[1, 1, 1], [1, 0, 0]],  # L
    [[1, 1, 1], [0, 0, 1]],  # J
    [[1, 1, 0], [0, 1, 1]],  # S
    [[0, 1, 1], [1, 1, 0]]  # Z
]

# Tetromino colors
TETROMINO_COLORS = [BLUE, GREEN, RED, GRAY, YELLOW, CYAN, PURPLE]

# Game settings
BLOCK_SIZE = 20
GRID_WIDTH = 10
GRID_HEIGHT = 20
PLAY_AREA_WIDTH = GRID_WIDTH * BLOCK_SIZE
PLAY_AREA_HEIGHT = GRID_HEIGHT * BLOCK_SIZE
PLAYER_AREA_WIDTH = PLAY_AREA_WIDTH // 3
PLAYER_AREA_HEIGHT = PLAY_AREA_HEIGHT

# Tetromino movement and rotation
class Tetromino:
    def __init__(self, shape, color):
        self.shape = shape
        self.color = color
        self.x = GRID_WIDTH // 2 - len(shape[0]) // 2
        self.y = 0
        self.rotation = 0

    def move(self, dx, dy):
        self.x += dx
        self.y += dy

    def rotate(self, clockwise=True):
        self.rotation = (self.rotation + (1 if clockwise else -1)) % len(self.shape)

# Game state
class GameState:
    def __init__(self):
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.current_tetrominos = [Tetromino(random.choice(TETROMINOS), TETROMINO_COLORS[i]) for i in range(3)]
        self.scores = [0, 0, 0]
        self.game_over = False

    def update(self):
        for i in range(3):
            if not self.check_collision(self.current_tetrominos[i], 0, 1):
                self.current_tetrominos[i].move(0, 1)
            else:
                self.lock_tetromino(i)
                self.current_tetrominos[i] = Tetromino(random.choice(TETROMINOS), TETROMINO_COLORS[i])
                self.check_lines()
                self.scores[i] += self.calculate_score(i)

    def check_collision(self, tetromino, dx, dy):
        for y, row in enumerate(tetromino.shape[tetromino.rotation]):
            for x, block in enumerate(row):
                if block:
                    new_x = tetromino.x + x + dx
                    new_y = tetromino.y + y + dy
                    if new_x < 0 or new_x >= GRID_WIDTH or new_y >= GRID_HEIGHT or self.grid[new_y][new_x]:
                        return True
        return False

    def lock_tetromino(self, player_index):
        for y, row in enumerate(self.current_tetrominos[player_index].shape[self.current_tetrominos[player_index].rotation]):
            for x, block in enumerate(row):
                if block:
                    self.grid[self.current_tetrominos[player_index].y + y][self.current_tetrominos[player_index].x + x] = self.current_tetrominos[player_index].color

    def check_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT):
            if all(self.grid[y]):
                self.grid.pop(y)
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        return lines_cleared

    def calculate_score(self, player_index):
        lines_cleared = self.check_lines()
        if lines_cleared == 1:
            return 40
        elif lines_cleared == 2:
            return 100
        elif lines_cleared == 3:
            return 300
        elif lines_cleared == 4:
            return 1200
        else:
            return 0

# Game loop
def main():
    game_state = GameState()

    clock = pygame.time.Clock()
    running = True
    while running:
        clock.tick(30)

        # Handle events
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    for i in range(3):
                        if not game_state.check_collision(game_state.current_tetrominos[i], -1, 0):
                            game_state.current_tetrominos[i].move(-1, 0)
                elif event.key == pygame.K_RIGHT:
                    for i in range(3):
                        if not game_state.check_collision(game_state.current_tetrominos[i], 1, 0):
                            game_state.current_tetrominos[i].move(1, 0)
                elif event.key == pygame.K_DOWN:
                    for i in range(3):
                        if not game_state.check_collision(game_state.current_tetrominos[i], 0, 1):
                            game_state.current_tetrominos[i].move(0, 1)
                elif event.key == pygame.K_UP:
                    for i in range(3):
                        if not game_state.check_collision(game_state.current_tetrominos[i], 0, 0, True):
                            game_state.current_tetrominos[i].rotate()

        # Update game state
        game_state.update()

        # Render the game
        game_window.fill(BLACK)

        # Draw the play area
        pygame.draw.rect(game_window, WHITE, (0, 0, PLAY_AREA_WIDTH, PLAY_AREA_HEIGHT), 2)

        # Draw the current tetrominos
        for i in range(3):
            for y, row in enumerate(game_state.current_tetrominos[i].shape[game_state.current_tetrominos[i].rotation]):
                for x, block in enumerate(row):
                    if block:
                        pygame.draw.rect(game_window, game_state.current_tetrominos[i].color,
                                        (game_state.current_tetrominos[i].x * BLOCK_SIZE + i * PLAYER_AREA_WIDTH,
                                         game_state.current_tetrominos[i].y * BLOCK_SIZE,
                                         BLOCK_SIZE, BLOCK_SIZE))

        # Draw the grid
        for y in range(GRID_HEIGHT):
            for x in range(GRID_WIDTH):
                if game_state.grid[y][x]:
                    pygame.draw.rect(game_window, game_state.grid[y][x],
                                    (x * BLOCK_SIZE + (i * PLAYER_AREA_WIDTH), y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

        # Draw the scores
        font = pygame.font.Font(None, 36)
        for i in range(3):
            score_text = font.render(f"Player {i+1}: {game_state.scores[i]}", True, WHITE)
            game_window.blit(score_text, (i * PLAYER_AREA_WIDTH, PLAY_AREA_HEIGHT + 20))

        pygame.display.flip()

    pygame.quit()

if __name__ == "__main__":
