import pygame
import random

# Initialize Pygame
pygame.init()

# Set up the window
WINDOW_WIDTH = 800
WINDOW_HEIGHT = 600
window = pygame.display.set_mode((WINDOW_WIDTH, WINDOW_HEIGHT))
pygame.display.set_caption("Tetris for Terzetto Players")

# Define colors
BLACK = (0, 0, 0)
WHITE = (255, 255, 255)
GRAY = (128, 128, 128)
BLUE = (0, 0, 255)
GREEN = (0, 255, 0)
RED = (255, 0, 0)

# Define Tetris block dimensions
BLOCK_SIZE = 30
GRID_WIDTH = 10
GRID_HEIGHT = 20

# Define Tetris shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I-shaped
    [[1, 1], [1, 1]],  # O-shaped
    [[1, 1, 1], [0, 1, 0]],  # T-shaped
    [[1, 1, 0], [0, 1, 1]],  # S-shaped
    [[0, 1, 1], [1, 1, 0]],  # Z-shaped
    [[1, 0, 0], [1, 1, 1]],  # J-shaped
    [[0, 0, 1], [1, 1, 1]]  # L-shaped
]

# Define Tetris player classes
class TetrisPlayer:
    def __init__(self, x, y, color):
        self.x = x
        self.y = y
        self.color = color
        self.score = 0
        self.current_shape = random.choice(SHAPES)
        self.current_rotation = 0
        self.current_x = 4
        self.current_y = 0
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]

    def move_left(self):
        if self.can_move_left():
            self.current_x -= 1

    def move_right(self):
        if self.can_move_right():
            self.current_x += 1

    def move_down(self):
        if self.can_move_down():
            self.current_y += 1
        else:
            self.lock_shape()
            self.clear_lines()
            self.current_shape = random.choice(SHAPES)
            self.current_rotation = 0
            self.current_x = 4
            self.current_y = 0

    def rotate(self):
        if self.can_rotate():
            self.current_rotation = (self.current_rotation + 1) % len(self.current_shape)

    def can_move_left(self):
        for y in range(len(self.current_shape[self.current_rotation])):
            for x in range(len(self.current_shape[self.current_rotation][y])):
                if self.current_shape[self.current_rotation][y][x] == 1:
                    if self.current_x + x - 1 < 0 or self.grid[self.current_y + y][self.current_x + x - 1] == 1:
                        return False
        return True

    def can_move_right(self):
