GRAY = (128, 128, 128)
RED = (255, 0, 0)
GREEN = (0, 255, 0)
BLUE = (0, 0, 255)

# Tetris block dimensions
BLOCK_SIZE = 20
GRID_WIDTH = 10
GRID_HEIGHT = 20

# Tetris piece shapes
TETRIS_PIECES = [
    [[1, 1, 1, 1]],  # I-piece
    [[1, 1], [1, 1]],  # O-piece
    [[1, 1, 1], [0, 1, 0]],  # T-piece
    [[1, 1, 0], [0, 1, 1]],  # S-piece
    [[0, 1, 1], [1, 1, 0]],  # Z-piece
    [[1, 0, 0], [1, 1, 1]],  # J-piece
    [[0, 0, 1], [1, 1, 1]]  # L-piece
]

# Player data
class Player:
    def __init__(self, name, color):
        self.name = name
        self.color = color
        self.score = 0
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]
        self.current_piece = None
        self.piece_position = [0, 0]
        self.piece_rotation = 0

    def move_piece(self, dx, dy):
        new_x = self.piece_position[0] + dx
        new_y = self.piece_position[1] + dy
        if self.check_valid_position(new_x, new_y, self.current_piece, self.piece_rotation):
            self.piece_position[0] = new_x
            self.piece_position[1] = new_y

    def rotate_piece(self, direction):
        new_rotation = (self.piece_rotation + direction) % len(self.current_piece)
        if self.check_valid_position(self.piece_position[0], self.piece_position[1], self.current_piece, new_rotation):
            self.piece_rotation = new_rotation

    def check_valid_position(self, x, y, piece, rotation):
        for i in range(len(piece[rotation])):
            for j in range(len(piece[rotation][i])):
                if piece[rotation][i][j] and (x + j < 0 or x + j >= GRID_WIDTH or y + i < 0 or y + i >= GRID_HEIGHT or self.grid[y + i][x + j]):
                    return False
        return True

    def drop_piece(self):
        while self.move_piece(0, 1):
            pass
        self.lock_piece()

    def lock_piece(self):
        for i in range(len(self.current_piece[self.piece_rotation])):
            for j in range(len(self.current_piece[self.piece_rotation][i])):
                if self.current_piece[self.piece_rotation][i][j]:
                    self.grid[self.piece_position[1] + i][self.piece_position[0] + j] = self.color
        self.clear_lines()
        self.choose_new_piece()

    def clear_lines(self):
        lines_cleared = 0
        for y in range(GRID_HEIGHT - 1, -1, -1):
            if all(self.grid[y]):
                self.grid.pop(y)
                self.grid.insert(0, [0 for _ in range(GRID_WIDTH)])
                lines_cleared += 1
        self.score += lines_cleared ** 2 * 100

    def choose_new_piece(self):
        self.current_piece = random.choice(TETRIS_PIECES)
        self.piece_position = [GRID_WIDTH // 2 - len(self.current_piece[0]) // 2, 0]
        self.piece_rotation = 0

# Game loop
def game_loop():
    players = [
        Player("Player 1", RED),
        Player("Player 2", GREEN),
        Player("Player 3", BLUE)
    ]

    clock = pygame.time.Clock()
    game_running = True
    while game_running:
        clock.tick(30)

        # Handle events
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                game_running = False

        # Update player positions and rotate pieces
        for player in players:
            keys = pygame.key.get_pressed()
            if keys[pygame.K_LEFT]:
                player.move_piece(-1, 0)
            if keys[pygame.K_RIGHT]:
                player.move_piece(1, 0)
            if keys[pygame.K_DOWN]:
                player.move_piece(0, 1)
            if keys[pygame.K_UP]:
                player.rotate_piece(1)
            if keys[pygame.K_SPACE]:
                player.drop_piece()

        # Draw the game window
        game_window.fill(BLACK)

        for player in players:
            # Draw the player's grid
            for y in range(GRID_HEIGHT):
                for x in range(GRID_WIDTH):
                    if player.grid[y][x]:
                        rect = pygame.Rect(x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE)
                        pygame.draw.rect(game_window, player.grid[y][x], rect)

            # Draw the player's current piece
            for i in range(len(player.current_piece[player.piece_rotation])):
                for j in range(len(player.current_piece[player.piece_rotation][i])):
                    if player.current_piece[player.piece_rotation][i][j]:
                        rect = pygame.Rect((player.piece_position[0] + j) * BLOCK_SIZE, (player.piece_position[1] + i) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE)
                        pygame.draw.rect(game_window, player.color, rect)

            # Draw the player's score
            score_text = f"{player.name}: {player.score}"
            score_surface = pygame.font.Font(None, 36).render(score_text, True, player.color)
            score_rect = score_surface.get_rect()
            score_rect.topleft = (10, 10 + (60 * players.index(player)))
            game_window.blit(score_surface, score_rect)

        pygame.display.flip()

    pygame.quit()

if __name__ == "__main__":
    game_loop()

