    color_index = random.randint(0, len(TETRIMINO_COLORS) - 1)
    return {
        "shape": TETRIMINO_SHAPES[shape_index],
        "color": TETRIMINO_COLORS[color_index],
        "x": 3,
        "y": 0,
        "player_index": player_index
    }

def check_collision(tetrimino):
    for y, row in enumerate(tetrimino["shape"]):
        for x, cell in enumerate(row):
            if cell and (
