                x + tetrimino["x"] >= FIELD_WIDTH or
                y + tetrimino["y"] >= FIELD_HEIGHT or
                game_field[y + tetrimino["y"]][x + tetrimino["x"]] != 0
            ):
                return True
    return False

def rotate_tetrimino(tetrimino):
    new_shape = list(zip(*reversed(tetrimino["shape"])))
    if not check_collision({"shape": new_shape, "x": tetrimino["x"], "y": tetrimino["y"], "color": tetrimino["color"], "player_index": tetrimino["player_index"]}):
