import pygame
import random

# Define game constants
WINDOW_WIDTH = 800
WINDOW_HEIGHT = 600
BLOCK_SIZE = 30
BOARD_WIDTH = 10
BOARD_HEIGHT = 20

# Define Tetri pieces
PIECES = [
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Square
    [(0, 0), (0, 1), (0, 2), (0, 3)],  # I
    [(0, 0), (0, 1), (0, 2), (1, 1)],  # T
    [(0, 0), (0, 1), (1, 1), (1, 2)],  # S
    [(0, 0), (0, 1), (1, 0), (1, 1)],  # Z
    [(0, 0), (1, 0), (1, 1), (1, 2)],  # J
    [(0, 0), (0, 1), (0, 2), (1, 0)]   # L
]

# Define Tetri piece colors
PIECE_COLORS = [(255, 255, 0), (0, 255, 255), (255, 0, 255), (0, 255, 0), (255, 0, 0), (0, 0, 255), (255, 165, 0)]

# Define game state
class GameState:
    def __init__(self):
        self.board = [[0 for _ in range(BOARD_WIDTH)] for _ in range(BOARD_HEIGHT)]
        self.current_piece = self.get_random_piece()
        self.current_piece_x = BOARD_WIDTH // 2 - 2
        self.current_piece_y = 0
        self.score = [0, 0, 0]
        self.player_scores = [0, 0, 0]

    def get_random_piece(self):
        return random.choice(PIECES)

    def rotate_piece(self):
        new_piece = [(-y, x) for x, y in self.current_piece]
        if self.check_valid_position(new_piece):
            self.current_piece = new_piece

    def move_piece(self, dx, dy):
        new_x = self.current_piece_x + dx
        new_y = self.current_piece_y + dy
        if self.check_valid_position(self.current_piece, new_x, new_y):
            self.current_piece_x = new_x
            self.current_piece_y = new_y

    def check_valid_position(self, piece, x=None, y=None):
        if x is None:
            x = self.current_piece_x
        if y is None:
            y = self.current_piece_y
        for dx, dy in piece:
            new_x = x + dx
            new_y = y + dy
            if new_x < 0 or new_x >= BOARD_WIDTH or new_y >= BOARD_HEIGHT or self.board[new_y][new_x]:
                return False
        return True

    def lock_piece(self):
        for dx, dy in self.current_piece:
            x = self.current_piece_x + dx
            y = self.current_piece_y + dy
            self.board[y][x] = self.current_piece_color

        self.clear_lines()
        self.current_piece = self.get_random_piece()
        self.current_piece_x = BOARD_WIDTH // 2 - 2
        self.current_piece_y = 0
        if not self.check_valid_position(self.current_piece):
            return True
        return False

    def clear_lines(self):
        rows_to_remove = []
        for y in range(BOARD_HEIGHT):
            if all(self.board[y]):
                rows_to_remove.append(y)

        if rows_to_remove:
            for y in rows_to_remove[::-1]:
                del self.board[y]
                self.board.insert(0, [0] * BOARD_WIDTH)
            self.update_scores(len(rows_to_remove))

    def update_scores(self, num_lines):
        for i in range(3):
            self.player_scores[i] += num_lines
            self.score[i] += num_lines * (i + 1)

# Define game loop
def main():
    pygame.init()
    screen = pygame.display.set_mode((WINDOW_WIDTH, WINDOW_HEIGHT))
    pygame.display.set_caption("Tetri")

    game_state = GameState()

    clock = pygame.time.Clock()
    running = True
    while running:
        clock.tick(60)

        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT:
                    game_state.move_piece(-1, 0)
                elif event.key == pygame.K_RIGHT:
                    game_state.move_piece(1, 0)
                elif event.key == pygame.K_DOWN:
                    game_state.move_piece(0, 1)
                elif event.key == pygame.K_UP:
                    game_state.rotate_piece()

        # Clear the screen
        screen.fill((0, 0, 0))

        # Draw the board
        for y in range(BOARD_HEIGHT):
            for x in range(BOARD_WIDTH):
                if game_state.board[y][x]:
                    pygame.draw.rect(screen, PIECE_COLORS[game_state.board[y][x] - 1], (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

        # Draw the current piece
        for dx, dy in game_state.current_piece:
            x = game_state.current_piece_x + dx
            y = game_state.current_piece_y + dy
            pygame.draw.rect(screen, PIECE_COLORS[PIECES.index(game_state.current_piece)], (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

        # Draw the scores
        font = pygame.font.Font(None, 36)
        for i in range(3):
            text = font.render(f"Player {i+1} Score: {game_state.player_scores[i]}", True, (255, 255, 255))
            screen.blit(text, (10, 10 + i * 50))

        # Update the display
        pygame.display.flip()

        # Move the piece down
        if game_state.check_valid_position(game_state.current_piece, game_state.current_piece_x, game_state.current_piece_y + 1):
            game_state.move_piece(0, 1)
        else:
            if game_state.lock_piece():
                running = False

if __name__ == "__main__":
