import random

class TetrisBoard:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.board = [[0 for _ in range(width)] for _ in range(height)]
        self.current_piece = None
        self.next_piece = None
        self.score = 0
        self.level = 1
        self.lines_cleared = 0

    def add_piece(self):
        if self.next_piece is None:
            self.next_piece = Piece(random.choice(["I", "O", "T", "S", "Z", "J", "L"]))
        self.current_piece = self.next_piece
        self.next_piece = Piece(random.choice(["I", "O", "T", "S", "Z", "J", "L"]))

    def move_piece(self, direction):
        if direction == "left":
            self.current_piece.move_left(self.board)
        elif direction == "right":
            self.current_piece.move_right(self.board)
        elif direction == "down":
            self.current_piece.move_down(self.board)
        elif direction == "rotate":
            self.current_piece.rotate(self.board)

    def check_lines(self):
        lines_cleared = 0
        for y in range(self.height):
            if all(self.board[y]):
                self.board.pop(y)
                self.board.insert(0, [0] * self.width)
                lines_cleared += 1
        self.lines_cleared += lines_cleared
        self.score += lines_cleared ** 2 * self.level
        self.level = 1 + self.lines_cleared // 10

class Piece:
    def __init__(self, shape):
        self.shape = shape
        self.rotation = 0
        self.x = 3
        self.y = 0
        self.shapes = {
            "I": [[(0, 0), (0, 1), (0, 2), (0, 3)],
                  [(0, 0), (1, 0), (2, 0), (3, 0)]],
            "O": [[(0, 0), (0, 1), (1, 0), (1, 1)]],
            "T": [[(0, 1), (1, 0), (1, 1), (1, 2)],
                  [(0, 0), (0, 1), (0, 2), (1, 1)],
                  [(0, 0), (1, 0), (1, 1), (2, 0)],
                  [(0, 1), (1, 0), (1, 1), (1, 2)]],
            "S": [[(0, 1), (0, 2), (1, 0), (1, 1)],
                  [(0, 0), (1, 0), (1, 1), (2, 1)]],
            "Z": [[(0, 0), (0, 1), (1, 1), (1, 2)],
                  [(0, 1), (1, 0), (1, 1), (2, 0)]],
            "J": [[(0, 0), (0, 1), (0, 2), (1, 2)],
                  [(0, 0), (0, 1), (1, 0), (2, 0)],
                  [(0, 0), (1, 0), (1, 1), (1, 2)],
                  [(0, 1), (1, 1), (2, 0), (2, 1)]],
            "L": [[(0, 2), (1, 0), (1, 1), (1, 2)],
                  [(0, 0), (0, 1), (1, 1), (2, 1)],
                  [(0, 0), (0, 1), (0, 2), (1, 0)],
                  [(0, 0), (1, 0), (2, 0), (2, 1)]]
        }

    def move_left(self, board):
        if self.x > 0 and all(board[self.y + y][self.x + x - 1] == 0 for x, y in self.shapes[self.shape][self.rotation]):
            self.x -= 1

    def move_right(self, board):
        if self.x < board[0] - len(self.shapes[self.shape][self.rotation][0]) and all(board[self.y + y][self.x + x + 1] == 0 for x, y in self.shapes[self.shape][self.rotation]):
            self.x += 1

    def move_down(self, board):
        if self.y < board - len(self.shapes[self.shape][self.rotation]) and all(board[self.y + y + 1][self.x + x] == 0 for x, y in self.shapes[self.shape][self.rotation]):
            self.y += 1
        else:
            for x, y in self.shapes[self.shape][self.rotation]:
                board[self.y + y][self.x + x] = 1
            board.check_lines()
            board.add_piece()

    def rotate(self, board):
        new_rotation = (self.rotation + 1) % len(self.shapes[self.shape])
        if all(0 <= self.x + x < board[0] and 0 <= self.y + y < board for x, y in self.shapes[self.shape][new_rotation]):
            self.rotation = new_rotation

