class Game:
    BOARD_WIDTH = 10
    BOARD_HEIGHT = 20

    def __init__(self, players):
        self.players = players
        self.board = [[0 for _ in range(self.BOARD_WIDTH)] for _ in range(self.BOARD_HEIGHT)]
        self.current_tetrimino = Tetrimino(random.randint(0, len(Tetrimino.SHAPES) - 1))
        self.game_over = False

    def update(self):
        if not self.game_over:
            self.move_down()
            if self.check_collision():
                self.lock_tetrimino()
                self.clear_lines()
                self.current_tetrimino = Tetrimino(random.randint(0, len(Tetrimino.SHAPES) - 1))
                if self.check_collision():
                    self.game_over = True

    def move_left(self):
        self.current_tetrimino.x -= 1
        if self.check_collision():
            self.current_tetrimino.x += 1

    def move_right(self):
        self.current_tetrimino.x += 1
        if self.check_collision():
            self.current_tetrimino.x -= 1

    def move_down(self):
        self.current_tetrimino.y += 1
        if self.check_collision():
            self.current_tetrimino.y -= 1

    def rotate_tetrimino(self):
        old_rotation = self.current_tetrimino.rotation
        self.current_tetrimino.rotate()
        if self.check_collision():
            self.current_tetrimino.rotation = old_rotation
            self.current_tetrimino.shape = [(-y, x) for x, y in self.current_tetrimino.shape]

    def check_collision(self):
        for x, y in self.current_tetrimino.shape:
            if y + self.current_tetrimino.y < 0 or y + self.current_tetrimino.y >= self.BOARD_HEIGHT or x + self.current_tetrimino.x < 0 or x + self.current_tetrimino.x >= self.BOARD_WIDTH or self.board[y + self.current_tetrimino.y][x + self.current_tetrimino.x] != 0:
                return True
        return False

    def lock_tetrimino(self):
        for x, y in self.current_tetrimino.shape:
            self.board[y + self.current_tetrimino.y][x + self.current_tetrimino.x] = self.current_tetrimino.color

    def clear_lines(self):
        lines_cleared = 0
        for y in range(self.BOARD_HEIGHT):
            if all(self.board[y]):
                self.board.pop(y)
                self.board.insert(0, [0] * self.BOARD_WIDTH)
                lines_cleared += 1
        for player in self.players:
            player.score += lines_cleared ** 2

