def draw_tetromino(player):
    for i, row in enumerate(tetrominos[player["rotation"]]):
        for j, cell in enumerate(row):
            board[player["position"][0] + i][player["position"][1] + j] = cell

def move_tetromino(player, dx, dy):
    new_position = [player["position"][0] + dy, player["position"][1] + dx]
    if all(0 <= new_position[i] < len(board) // (i+1) for i in range(2)):
        if all(board[new_position[0]][new_position[1]] == 0 for row in tetrominos[player["rotation"]] for cell in row):
            player["position"] = new_position
            return True
    return False

def rotate_tetromino(player):
    new_rotation = (player["rotation"] + 1) % len(tetrominos)
    if all(0 <= player["position"][0] + j < len(board) and 0 <= player["position"][1] + i < len(board[0]) and board[player["position"][0] + j][player["position"][1] + i] == 0 for i, row in enumerate(tetrominos[new_rotation]) for j, cell in enumerate(row) if cell):
        player["rotation"] = new_rotation
        return True
    return False

def update_score(player):
    lines_cleared = 0
    for i in range(len(board)):
        if all(board[i][j] for j in range(len(board[i]))):
            for j in range(len(board[i])):
                board[i][j] = 0
            for j in range(i, 0, -1):
                board[j] = board[j-1]
            board[0] = [0 for _ in range(len(board[0]))]
            lines_cleared += 1
    player["score"] += 100 * lines_cleared ** 2

def game_loop():
    while True:
        for player in players:
            draw_board()
            print(f"Player {players.index(player) + 1} score: {player['score']}")
            draw_tetromino(player)

