        [[1, 1, 0], [0, 1, 1]],  # S
        [[0, 1, 1], [1, 1, 0]]  # Z
    ]

    def __init__(self, x, y, shape_index):
        self.x = x
        self.y = y
        self.shape = self.SHAPES[shape_index]
        self.color = (random.randint(50, 255), random.randint(50, 255), random.randint(50, 255))

    def rotate(self):
        self.shape = list(map(list, zip(*self.shape[::-1])))

    def move_left(self):
        self.x -= 1

    def move_right(self):
        self.x += 1

    def move_down(self):
        self.y += 1

class Player:
    """Represents a Tetris player"""
    def __init__(self, name, x, y):
        self.name = name
        self.score = 0
        self.board = [[0 for _ in range(10)] for _ in range(20)]
        self.current_tetromino = Tetromino(x, y, random.randint(0, 6))
        self.next_tetromino = Tetromino(x + 5, y, random.randint(0, 6))

    def update_score(self, lines_cleared):
        self.score += lines_cleared * 100

    def check_collision(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, cell in enumerate(row):
                if cell and (tetromino.x + x < 0 or tetromino.x + x >= 10 or tetromino.y + y >= 20 or self.board[tetromino.y + y][tetromino.x + x]):
                    return True
        return False

    def lock_tetromino(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    self.board[tetromino.y + y][tetromino.x + x] = cell
        self.current_tetromino = self.next_tetromino
        self.next_tetromino = Tetromino(tetromino.x + 5, tetromino.y, random.randint(0, 6))

    def clear_lines(self):
        lines_cleared = 0
        for y in range(19, -1, -1):
            if all(self.board[y]):
                self.board.pop(y)
                self.board.insert(0, [0] * 10)
                lines_cleared += 1
        return lines_cleared

class TetrisGame:
    """Represents the Tetris game"""
    def __init__(self):
        pygame.init()
        self.screen = pygame.display.set_mode((800, 600))
        pygame.display.set_caption("Tetris")
        self.clock = pygame.time.Clock()
        self.players = [
            Player("Player 1", 2, 0),
            Player("Player 2", 12, 0),
            Player("Player 3", 22, 0)
        ]
        self.running = True

    def run(self):
        while self.running:
            self.clock.tick(60)
            self.handle_events()
            self.update_game_state()
            self.render_game()

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                self.running = False

    def update_game_state(self):
        for player in self.players:
            if not self.check_player_input(player):
                if self.check_collision(player.current_tetromino, player):
                    player.lock_tetromino(player.current_tetromino)
                    lines_cleared = player.clear_lines()
                    player.update_score(lines_cleared)
                    if lines_cleared > 0:
                        self.update_other_players_scores(player, lines_cleared)
                else:
                    player.current_tetromino.move_down()

    def check_player_input(self, player):
        keys = pygame.key.get_pressed()
        if keys[pygame.K_LEFT]:
            player.current_tetromino.move_left()
            if self.check_collision(player.current_tetromino, player):
                player.current_tetromino.move_right()
        elif keys[pygame.K_RIGHT]:
            player.current_tetromino.move_right()
            if self.check_collision(player.current_tetromino, player):
                player.current_tetromino.move_left()
        elif keys[pygame.K_DOWN]:
            player.current_tetromino.move_down()
            if self.check_collision(player.current_tetromino, player):
                player.current_tetromino.move_up()
        elif keys[pygame.K_SPACE]:
            while not self.check_collision(player.current_tetromino, player):
                player.current_tetromino.move_down()
            player.lock_tetromino(player.current_tetromino)
            lines_cleared = player.clear_lines()
            player.update_score(lines_cleared)
            if lines_cleared > 0:
                self.update_other_players_scores(player, lines_cleared)
        elif keys[pygame.K_UP]:
            player.current_tetromino.rotate()
            if self.check_collision(player.current_tetromino, player):
                player.current_tetromino.rotate()
                player.current_tetromino.rotate()
                player.current_tetromino.rotate()
        else:
            return False
        return True

    def check_collision(self, tetromino, player):
        return player.check_collision(tetromino)

    def update_other_players_scores(self, player, lines_cleared):
        for p in self.players:
            if p != player:
                p.update_score(lines_cleared // 2)

    def render_game(self):
        self.screen.fill((0, 0, 0))

        for player in self.players:
            self.render_player(player)

        pygame.display.flip()

    def render_player(self, player):
        for y, row in enumerate(player.board):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(self.screen, player.current_tetromino.color, (x * 30 + player.x * 300, y * 30, 30, 30))

        self.render_tetromino(player.current_tetromino)
        self.render_tetromino(player.next_tetromino)

        font = pygame.font.Font(None, 36)
        text = font.render(f"{player.name}: {player.score}", True, (255, 255, 255))
        self.screen.blit(text, (player.x * 300 + 10, 550))

    def render_tetromino(self, tetromino):
        for y, row in enumerate(tetromino.shape):
            for x, cell in enumerate(row):
                if cell:
                    pygame.draw.rect(self.screen, tetromino.color, (tetromino.x * 30 + x * 30, tetromino.y * 30 + y * 30, 30, 30))

