    [[1, 0, 0], [1, 1, 1]],  # J-shape
    [[0, 0, 1], [1, 1, 1]]  # L-shape
]

class TetrisBlock:
    def __init__(self, shape, color):
        self.shape = shape
        self.color = color
        self.x = 3
        self.y = 0
        self.rotation = 0

    def rotate(self):
        self.rotation = (self.rotation + 1) % len(self.shape)

    def move_left(self):
        self.x -= 1

    def move_right(self):
        self.x += 1

    def move_down(self):
        self.y += 1

    def draw(self, screen):
        for row in range(len(self.shape[self.rotation])):
            for col in range(len(self.shape[self.rotation][row])):
                if self.shape[self.rotation][row][col] == 1:
                    pygame.draw.rect(screen, self.color, (
                        (self.x + col) * BLOCK_SIZE,
                        (self.y + row) * BLOCK_SIZE,
                        BLOCK_SIZE,
                        BLOCK_SIZE
                    ))

class TetrisGrid:
    def __init__(self):
        self.grid = [[0 for _ in range(GRID_WIDTH)] for _ in range(GRID_HEIGHT)]

    def add_block(self, block):
        for row in range(len(block.shape[block.rotation])):
            for col in range(len(block.shape[block.rotation][row])):
                if block.shape[block.rotation][row][col] == 1:
                    self.grid[block.y + row][block.x + col] = block.color

    def clear_lines(self):
        lines_cleared = 0
        for row in range(GRID_HEIGHT - 1, -1, -1):
            if all(self.grid[row]):
                self.grid.pop(row)
                self.grid.insert(0, [0] * GRID_WIDTH)
                lines_cleared += 1
        return lines_cleared

    def draw(self, screen):
        for row in range(GRID_HEIGHT):
            for col in range(GRID_WIDTH):
                if self.grid[row][col] != 0:
                    pygame.draw.rect(screen, self.grid[row][col], (
                        col * BLOCK_SIZE,
                        row * BLOCK_SIZE,
                        BLOCK_SIZE,
                        BLOCK_SIZE
