BLOCK_SIZE = 30
GRID_ROWS = 20
GRID_COLS = 10

# Define Tetri shapes
SHAPES = [
    [[1, 1, 1, 1]],  # I-shaped Tetri
    [[1, 1], [1, 1]],  # O-shaped Tetri
    [[1, 1, 0], [0, 1, 1]],  # Z-shaped Tetri
    [[0, 1, 1], [1, 1, 0]],  # S-shaped Tetri
    [[1, 0, 0], [1, 1, 1]],  # J-shaped Tetri
    [[0, 0, 1], [1, 1, 1]],  # L-shaped Tetri
    [[1, 1, 1], [0, 1, 0]]  # T-shaped Tetri
]

# Define Tetri game state
class TetriGame:
    def __init__(self):
        self.grid = [[0 for _ in range(GRID_COLS)] for _ in range(GRID_ROWS)]
        self.current_shape = random.choice(SHAPES)
        self.shape_x = GRID_COLS // 2 - len(self.current_shape[0]) // 2
        self.shape_y = 0
        self.score = 0
        self.game_over = False

    def move_left(self):
        if self.check_valid_position(dx=-1):
            self.shape_x -= 1

    def move_right(self):
        if self.check_valid_position(dx=1):
            self.shape_x += 1

    def move_down(self):
        if self.check_valid_position(dy=1):
            self.shape_y += 1
        else:
            self.lock_shape()
            self.clear_rows()
            self.spawn_new_shape()

    def rotate(self):
        rotated_shape = [list(reversed(col)) for col in zip(*self.current_shape)]
        if self.check_valid_position(shape=rotated_shape):
            self.current_shape = rotated_shape

    def check_valid_position(self, dx=0, dy=0, shape=None):
        if shape is None:
            shape = self.current_shape
        for y, row in enumerate(shape):
            for x, block in enumerate(row):
                new_x = self.shape_x + x + dx
                new_y = self.shape_y + y + dy
                if new_x < 0 or new_x >= GRID_COLS or new_y >= GRID_ROWS:
                    return False
                if new_y >= 0 and self.grid[new_y][new_x]:
                    return False
        return True

    def lock_shape(self):
        for y, row in enumerate(self.current_shape):
            for x, block in enumerate(row):
                if block:
                    if self.shape_y + y < 0:
                        self.game_over = True
                        return
                    self.grid[self.shape_y + y][self.shape_x + x] = block

    def clear_rows(self):
        rows_to_remove = [y for y, row in enumerate(self.grid) if all(block for block in row)]
        if rows_to_remove:
            self.score += len(rows_to_remove) * 100
            for y in rows_to_remove:
                del self.grid[y]
                self.grid.insert(0, [0] * GRID_COLS)

    def spawn_new_shape(self):
        self.current_shape = random.choice(SHAPES)
        self.shape_x = GRID_COLS // 2 - len(self.current_shape[0]) // 2
        self.shape_y = 0

    def draw_grid(self):
        for y in range(GRID_ROWS):
            for x in range(GRID_COLS):
                if self.grid[y][x]:
                    pygame.draw.rect(game_window, GRAY, (x * BLOCK_SIZE, y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

    def draw_current_shape(self):
        for y, row in enumerate(self.current_shape):
            for x, block in enumerate(row):
                if block:
                    pygame.draw.rect(game_window, WHITE, ((self.shape_x + x) * BLOCK_SIZE, (self.shape_y + y) * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE))

    def draw_score(self):
        font = pygame.font.Font(None, 36)
        score_text = font.render(f"Score: {self.score}", True, WHITE)
        game_window.blit(score_text, (10, 10))

    def run(self):
        clock = pygame.time.Clock()
        while not self.game_over:
            clock.tick(10)
            for event in pygame.event.get():
                if event.type == pygame.QUIT:
                    self.game_over = True
                elif event.type == pygame.KEYDOWN:
                    if event.key == pygame.K_LEFT:
                        self.move_left()
                    elif event.key == pygame.K_RIGHT:
                        self.move_right()
                    elif event.key == pygame.K_DOWN:
                        self.move_down()
                    elif event.key == pygame.K_SPACE:
                        self.rotate()

            game_window.fill(BLACK)
            self.draw_grid()
            self.draw_current_shape()
            self.draw_score()
            pygame.display.flip()

        pygame.quit()

if __name__ == "__main__":
    game = TetriGame()
    game.run()

