class TetrisGame:
    def __init__(self, player1, player2, player3):
        self.players = [player1, player2, player3]

    def start_game(self):
        while True:
            for player in self.players:
                # Get the player's move
                move = random.choice(['left', 'right', 'rotate', 'drop'])
                if move == 'left':
                    player.move_left()
                elif move == 'right':
                    player.move_right()
                elif move == 'rotate':
                    player.rotate()
                elif move == 'drop':
                    player.drop()

                # Update the player's score and board
                lines_cleared = 0
                player.update_score(lines_cleared)
                player.draw_board()

            # Check for collisions and update the game state
            time.sleep(0.5)

    def get_player_scores(self):
        # Return a list of the players' scores
        return [player.score for player in self.players]

    def get_player_contributions(self):
        # Calculate the contribution of each player to the overall score
        total_score = sum(self.get_player_scores())
        contributions = [player.score / total_score for player in self.players]
        return contributions

